import { describe, it, expect } from 'vitest'
import { encodeFunctionData } from 'viem'
import { noxaLauncherAbi } from '../../src/rails/abis.js'

/**
 * Proves `noxaLauncherAbi`'s `launchToken` reproduces a REAL, SUCCESSFUL
 * historical NOXA launch transaction's calldata byte-for-byte, selector
 * included. All fields below were decoded from the real transaction's raw
 * calldata via `viem`'s own `decodeFunctionData` (not hand-transcribed) and
 * this test re-encodes them and diffs against the original bytes.
 */
describe('NOXA launchToken calldata', () => {
  it('reproduces the real "ROBIN DOG" (ROBINDOG) launch tx byte-for-byte', () => {
    // Real tx: 0x63da3b0a80cbc836806ed055ed797667e7ec59391cf7aeb5a3dcfeb9152756d0
    // to: 0xD9eC2db5f3D1b236843925949fe5bd8a3836FCcB (NOXA launchFactory), mainnet 4663
    // status: 0x1 (SUCCESS — 18 logs emitted, TokenLaunched fired), value 0.1405 ETH
    const REAL_CALLDATA = ''

    const built = encodeFunctionData({
      abi: noxaLauncherAbi,
      functionName: 'launchToken',
      args: [
        {
          name: "ROBIN DOG",
          symbol: "ROBINDOG",
          logo: "ipfs://bafkreih6upnqufpv57qfpnfthtjcdwgdblmsmoa76mjngziclc4kcizv6e",
          description: "",
          socials: {
            telegram: "https://t.me/robinhooddogofficialportal",
            twitter: "",
            discord: "",
            website: "",
            farcaster: "",
          },
          devWallet: "0x30B0A6c97Cf015495e022219bA0F9a3787c90177",
        },
        0n,
        0n,
        "0x325efe279a17234d81d7257365a70cce7246bc06be3d36c9d21d0a07e5644e9b",
      ],
    })

    expect(built.toLowerCase()).toBe(REAL_CALLDATA.toLowerCase())
    expect(built.slice(0, 10)).toBe('0x686399cb')
  })
})
